@startuml
skinparam packageStyle rectangle
skinparam shadowing false
skinparam classAttributeIconSize 0

package "de" {
  package "thro" {
    package "inf" {
      package "prg3" {
        package "a13" {
          package "tweets" {

            package "generators" {

              interface TweetStreamGenerator {
                +getTweetStream(): Stream<Tweet>
              }

              class OnlineTweetStreamGenerator
              class OfflineTweetStreamGenerator

              OnlineTweetStreamGenerator ..|> TweetStreamGenerator
              OfflineTweetStreamGenerator ..|> TweetStreamGenerator
            }

            class TweetStreamFactory {
              -instance: TweetStreamFactory
              +getInstance(): TweetStreamFactory
              +isOnlineAvailable(): boolean
              +getTweetsStream(tweetSource: TweetSource): Stream<Tweet>
            }

            enum TweetSource {
              ONLINE
              OFFLINE
            }

            TweetStreamFactory --> generators.OnlineTweetStreamGenerator : Instantiates and returns
            TweetStreamFactory --> generators.OfflineTweetStreamGenerator : Instantiates and returns
          }
        }
      }
    }
  }
}
@enduml
